UPDATE t_p45929761_bold_move_project.ai_system_prompt
SET content = REPLACE(content,
E'ПРАВИЛО 6 — НИШИ ДЛЯ ШТОР:',
E'ПРАВИЛО 5б — ЧИСЛИТЕЛЬНЫЕ ПЕРЕД ПОЗИЦИЕЙ:\nЕсли монтажник говорит «2 профиля», «два профиля», «3 штуки», «две ниши» и т.п. —\nчисло ПЕРЕД позицией означает КОЛИЧЕСТВО (qty), а НЕ длину.\nПример: «2 ниши ПК-14 по левой стене» → qty = длина_стены × 2.\nПример: «по одному профилю с каждой стороны» → qty = длина_одной_стороны × 1.\nЕсли числительное не указано — qty = длина стены как обычно.\n\nПРАВИЛО 6 — НИШИ ДЛЯ ШТОР:')
WHERE id = 1